use std::collections::BTreeMap;
use std::sync::Mutex;

struct LayerAnalyzer {
    sorted_sizes: Mutex<BTreeMap<u64, usize>>
}

impl LayerAnalyzer {
    fn new() -> Self {
        LayerAnalyzer {
            sorted_sizes: Mutex::new(BTreeMap::new())
        }
    }

    fn record_size(&self, file_hash: u64, size_bytes: usize) {
        let mut map = self.sorted_sizes.lock().unwrap();
        if let Some(count) = map.get_mut(&file_hash) {
            *count += size_bytes;
        } else {
            map.insert(file_hash, size_bytes);
        }
    }

    fn calculate_total_size(&self) -> usize {
        let map = self.sorted_sizes.lock().unwrap();
        map.values().fold(0, |acc, count| acc + count)
    }
}

fn main() {
    let analyzer = LayerAnalyzer::new();

    analyzer.record_size(12345, 1024);
    analyzer.record_size(67890, 512);
    analyzer.record_size(12345, 2048);

    let total = analyzer.calculate_total_size();
    println!("Total size recorded: {}", total);
}

use std::collections::BTreeMap;

struct BuildTracker {
    dependencies: BTreeMap<String, String>,
}

impl BuildTracker {
    fn new() -> Self {
        BuildTracker { 
            dependencies: BTreeMap::new()
        }
    }

    fn register_dependency(&mut self, key: &str, value: impl AsRef<str>) {
        let key_string = key.to_owned();
        self.dependencies.insert(key_string, value.as_ref().to_owned());
    }

    fn get_ordered_keys(&self) -> Vec<&String> {
        self.dependencies.keys().collect()
    }

    fn find_next_build_target(&self, _current_state: &str) -> Option<String> {
        let mut sorted_deps = self.dependencies.iter().map(|(k, v)| (k.as_str(), v));
        sorted_deps.next()
        .map(|(key, value)| format!("{}: {}", key, value)) 
    }
}

fn main() {
    let mut tracker = BuildTracker::new();
    tracker.register_dependency("CoreLib", "SourceCodeA");
    tracker.register_dependency("Utils", "SourceCodeB");
    tracker.register_dependency("MainApp", "EntrypointC");

    println!("--- Build Dependency Analysis ---n");
    if let Some(next) = tracker.find_next_build_target("InitialRun") {
        println!("Next event payload detected: {}", next);
    }

    let ordered_keys = tracker.get_ordered_keys();
    println!("All tracked build targets in order: {:?}", ordered_keys);
}

use std::collections::BTreeMap;

struct BlogEngine {
    sorted_posts: BTreeMap<String, String>,
}

impl BlogEngine {
    fn new() -> Self {
        BlogEngine {
            sorted_posts: BTreeMap::new(),
        }
    }

    fn add_post(&mut self, timestamp: &str, content: &str) {
        self.sorted_posts.insert(timestamp.to_string(), content.to_string());
    }

    fn display_all_posts(&self) -> Vec<String> {
        let mut ordered_output = Vec::new();
        for (key, value) in &self.sorted_posts {
            let formatted_post = format!("Time: {}nContent: {}", key, value);
            ordered_output.push(formatted_post);
        }
        ordered_output
    }
}

fn main() {
    let mut engine = BlogEngine::new();
    engine.add_post("2023-10-27T14:30:00Z", "First draft content for the new feature.");
    engine.add_post("2023-10-26T09:00:00Z", "Quick thoughts before I left the office today.");
    engine.add_post("2023-10-27T10:15:00Z", "This is the middle post that needs to appear second.");

    let posts = engine.display_all_posts();
    for (i, post) in posts.iter().enumerate() {
        println!("--- Post {} ---n{}", i + 1, post);
    }
}

use std::collections::BTreeMap;

struct ConfigStore {
    settings: BTreeMap<String, String>,
}

impl ConfigStore {
    fn new() -> Self {
        ConfigStore {
            settings: BTreeMap::new()
        }
    }

    fn set_setting(&mut self, key: String, value: String) {
        self.settings.insert(key, value);
    }

    fn get_sorted_keys(&self) -> Vec<String> {
        self.settings.keys().cloned().collect()
    }

    fn print_all_settings(&self) {
        println!("--- Sorted Configuration Settings ---");
        for (key, value) in self.settings.iter() {
            println!("Key: {}", key);
            println!("Value: {}", value);
        }
        println!("-------------------------------------");
    }
}

fn main() {
    let mut store = ConfigStore::new();
    store.set_setting("api_endpoint".to_string(), "https://backend.example.com/v1".to_string());
    store.set_setting("theme_mode".to_string(), "dark".to_string());
    store.set_setting("user_session_id".to_string(), "xyz987".to_string());

    store.print_all_settings();
}

use std::collections::BTreeMap;
use std::sync::Arc;

struct LogEntry {
    timestamp: u64,
    data: String,
}

fn process_log_entries(identifiers: Vec<u64>, payloads: Vec<String>) -> BTreeMap<u64, LogEntry> {
    let mut ordered_map = BTreeMap::new();

    for i in 0..identifiers.len() {
        let key = identifiers[i];
        let data = payloads[i].clone();

        let entry = LogEntry {
            timestamp: key,
            data: data,
        };
        ordered_map.insert(key, entry);
    }
    ordered_map
}

fn main() {
    let node_ids = vec![101, 205, 330, 50];
    let state_data = vec!["Commit A".to_string(), "Heartbeat B".to_string(), "Vote C".to_string(), "Initial Sync".to_string()];

    let consensus_log = process_log_entries(node_ids, state_data);

    println!("n--- Consensus Log State ---n");
    for (id, entry) in consensus_log.iter() {
        println!("ID: {}", id);
        println!("  Data: {}", entry.data);
        println!("  Time: {}", entry.timestamp);
    }
}
